class Solution:
    def minSessions(self, tasks, sessionTime):
        n = len(tasks)
        order = sorted(tasks, reverse=True)
        def feasible(k):
            bins = [0] * k
            def backtrack(i):
                if i == n:
                    return True
                seen = set()
                for b in range(k):
                    if bins[b] in seen:
                        continue
                    seen.add(bins[b])
                    if bins[b] + order[i] <= sessionTime:
                        bins[b] += order[i]
                        if backtrack(i + 1):
                            return True
                        bins[b] -= order[i]
                    if bins[b] == 0:
                        break
                return False
            return backtrack(0)
        k = 1
        while not feasible(k):
            k += 1
        return k

