class Solution:
    def minSessions(self, tasks, sessionTime):
        n = len(tasks)
        subset_time = [0] * (1 << n)
        for mask in range(1, 1 << n):
            i = (mask & -mask).bit_length() - 1
            subset_time[mask] = subset_time[mask ^ (1 << i)] + tasks[i]
        INF = float('inf')
        dp = [INF] * (1 << n)
        dp[0] = 0
        for mask in range(1, 1 << n):
            sub = mask
            while sub > 0:
                if subset_time[sub] <= sessionTime and dp[mask ^ sub] + 1 < dp[mask]:
                    dp[mask] = dp[mask ^ sub] + 1
                sub = (sub - 1) & mask
        return dp[(1 << n) - 1]

