var minSessions = function(tasks, sessionTime) {
    const n = tasks.length;
    const subsetTime = new Array(1 << n).fill(0);
    for (let mask = 1; mask < (1 << n); mask++) {
        const i = 31 - Math.clz32(mask & -mask);
        subsetTime[mask] = subsetTime[mask ^ (1 << i)] + tasks[i];
    }
    const INF = Infinity;
    const dp = new Array(1 << n).fill(INF);
    dp[0] = 0;
    for (let mask = 1; mask < (1 << n); mask++) {
        let sub = mask;
        while (sub > 0) {
            if (subsetTime[sub] <= sessionTime && dp[mask ^ sub] + 1 < dp[mask]) {
                dp[mask] = dp[mask ^ sub] + 1;
            }
            sub = (sub - 1) & mask;
        }
    }
    return dp[(1 << n) - 1];
};
